template <typename T>
__forceinline__ __device__ void BlockReduce(T &val) {
  // Assumes blockDim.x == GPU_NUM_THREADS (256) but works for any multiple of 32 up to GPU_NUM_THREADS
  const unsigned FULL_MASK = 0xFFFFFFFFu;
  int lane = threadIdx.x & 31;
  int warp = threadIdx.x >> 5;

  T v = val;

  #pragma unroll
  for (int offset = 16; offset > 0; offset >>= 1) {
    v += __shfl_down_sync(FULL_MASK, v, offset);
  }

  __shared__ T s_partials[GPU_NUM_THREADS / 32]; // 8 lanes for 256 threads

  if (lane == 0) {
    s_partials[warp] = v;
  }

  __syncthreads();

  T sum = T(0);
  if (warp == 0) {
    // Number of active warps may be < GPU_NUM_THREADS/32 if blockDim.x < GPU_NUM_THREADS
    const int num_warps = (blockDim.x + 31) >> 5;
    sum = (lane < num_warps) ? s_partials[lane] : T(0);
    #pragma unroll
    for (int offset = 16; offset > 0; offset >>= 1) {
      sum += __shfl_down_sync(FULL_MASK, sum, offset);
    }
  }

  if (threadIdx.x == 0) {
    val = sum;
  }
}

