  // Ping-pong shared buffers avoid end-of-iteration barriers for shared re-use
  __shared__ int   s_label_buf[2];
  __shared__ float s_label_pred_buf[2];

  int count = 0;

  for (int row = blockIdx.x; row < N; row += gridDim.x) {

    // Broadcast label and label_pred exactly once per row (reduces global traffic and scoreboard stalls)
    const int buf = row & 1;
