  for (int row = blockIdx.x; row < N; row += gridDim.x) {

    // Start-of-iteration barrier: ensures prior iteration finished using shared memory
    __syncthreads();

    if (threadIdx.x == 0) {
      s_label = labelData[row];
      s_label_pred = Xdata[row * D + s_label];
