/*
Mathematical specification for BlockAdjDiffKernel and its host-side reference:

Preconditions:
- Let BLOCK_THREADS be the kernel blockDim.x and ITEMS_PER_THREAD = 4.
- Let items_per_block = BLOCK_THREADS * ITEMS_PER_THREAD.
- num_items is rounded up to the nearest multiple of items_per_block.
- d_in and d_out each point to arrays of at least num_items contiguous int elements.
- The int4 load/store interfaces access aligned storage; cudaMalloc guarantees alignment.

Postconditions (per block b, 0 <= b < gridDim.x):
- For block base B = b * items_per_block and 0 <= k < items_per_block:
    d_out[B + k] =
      d_in[B + k]                  if k == 0
      d_in[B + k] - d_in[B + k-1]  otherwise

Loop invariants (host reference computation inside Test):
- For fixed block b:
  Invariant I1 at start of iteration i (0 <= i <= items_per_block):
    For all 0 <= j < i:
      r_out[B + j] =
        h_in[B + j]                  if j == 0
        h_in[B + j] - h_in[B + j-1]  otherwise
  Initialization: holds for i = 0 (no elements computed).
  Maintenance: computing out[B + i] from h_in preserves I1 for i+1.
  Termination: at i = items_per_block, all elements in the block satisfy the postcondition.

Kernel invariants (enforced by CUB BlockAdjacentDifference):
- Each thread t in block handles a contiguous 4-tuple:
    local indices j in {0,1,2,3} map to global index g = B + t*4 + j.
- CUB::BlockAdjacentDifference with SubtractLeft ensures:
  For each thread t and j:
    thread_data[j] =
      d_in[g]                  if (t == 0 and j == 0)
      d_in[g] - d_in[g-1]      otherwise
  This matches the postcondition per-block and does not cross block boundaries.

Proof of semantic preservation after optimization:
- Rounding num_items up to a multiple of items_per_block guarantees:
  (a) Every launched thread has 4 valid elements to process (no out-of-bounds access).
  (b) int4 vectorized loads/stores are fully coalesced and aligned.
- The host-side reference loop invariant I1 is unchanged; only the iteration space size may
  grow due to padding, but both the kernel and the reference compute over the same padded size.
- CUB’s semantics remain unchanged; adding __launch_bounds__ does not alter behavior.
- Therefore, the postconditions hold for all processed elements, preserving correctness.
*/

struct CustomDifference
{
  template <typename DataType>
  __device__ DataType operator()(DataType &lhs, DataType &rhs)
  {
    return lhs - rhs;
  }
};

template <int BLOCK_THREADS>
__launch_bounds__(BLOCK_THREADS)
__global__ void BlockAdjDiffKernel(const int* d_in, int* d_out)
{
  using BlockAdjacentDifferenceT = cub::BlockAdjacentDifference<int, BLOCK_THREADS>;

  __shared__ typename BlockAdjacentDifferenceT::TempStorage temp_storage;

  const int idx = blockIdx.x * blockDim.x + threadIdx.x;

  // Ensure register-resident, 16B-aligned per-thread tile for vectorized access
  alignas(16) int thread_data[4];

  // Vectorized, coalesced, and aligned load of 4 int values per thread
  reinterpret_cast<int4*>(thread_data)[0] = reinterpret_cast<const int4*>(d_in)[idx];

  // Perform block-level adjacent difference with a custom functor
  BlockAdjacentDifferenceT(temp_storage).SubtractLeft(
      thread_data,
      thread_data,
      CustomDifference());

  // Vectorized, coalesced, and aligned store of 4 int values per thread
  reinterpret_cast<int4*>(d_out)[idx] = reinterpret_cast<int4*>(thread_data)[0];
}

void Initialize(int* h_in, int num_items)
{
  for (int i = 0; i < num_items; ++i)
  {
    h_in[i] = i % 17;
  }
}

template <int BLOCK_THREADS>
void Test(int num_items, int repeat)
{
  const int ITEMS_PER_THREAD = 4;

  // Round up to a full block tile to maintain coalesced int4 accesses
  const int items_per_block = BLOCK_THREADS * ITEMS_PER_THREAD;
  num_items = (num_items + items_per_block - 1) / items_per_block * items_per_block;

  int* h_in = new int[num_items];
  int* h_out = new int[num_items];
  int* r_out = new int[num_items];

  Initialize(h_in, num_items);

  int* d_in  = nullptr;
  int* d_out = nullptr;
  cudaMalloc((void**) &d_in, sizeof(int) * num_items);
  cudaMalloc((void**) &d_out, sizeof(int) * num_items);

  const int grid_size = num_items / items_per_block;
  dim3 grid (grid_size);
  dim3 block (BLOCK_THREADS);

  cudaMemcpy(d_in, h_in, sizeof(int) * num_items, cudaMemcpyHostToDevice);

  // Warmup
  for (int i = 0; i < repeat; i++) {
    BlockAdjDiffKernel<BLOCK_THREADS><<<grid, block>>>(d_in, d_out);
  }
  cudaMemcpy(h_out, d_out, sizeof(int) * num_items, cudaMemcpyDeviceToHost);

  // Reference computation per block:
  // Invariant I1: after iteration i, r_out[B..B+i-1] satisfies the postcondition.
  for (int b = 0; b < grid_size; b++) {
    auto in = h_in + b * items_per_block;
    auto out = r_out + b * items_per_block;
    for (int i = 0; i < items_per_block; i++) {
      out[i] = (i - 1) < 0 ? in[i] : in[i] - in[i-1];
    }
  }

  int compare = memcmp(r_out, h_out, sizeof(int) * num_items);
  printf("%s\n", compare ? "FAIL" : "PASS");

  auto start = std::chrono::steady_clock::now();

  for (int i = 0; i < repeat; i++) {
    BlockAdjDiffKernel<BLOCK_THREADS><<<grid, block>>>(d_in, d_out);
  }

  cudaDeviceSynchronize();
  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  printf("Average execution time of the kernel: %f (us)\n", (time * 1e-3f) / repeat);

  if (h_in) delete[] h_in;
  if (h_out) delete[] h_out;
  if (r_out) delete[] r_out;
  if (d_in) cudaFree(d_in);
  if (d_out) cudaFree(d_out);
}

int main(int argc, char** argv)
{
  if (argc != 3) {
    printf("Usage: %s <number of elements> <repeat>\n", argv[0]);
    return 1;
  }
  const int nelems = atoi(argv[1]);
  const int repeat = atoi(argv[2]);

  Test<  64>(nelems, repeat);
  Test< 128>(nelems, repeat);
  Test< 256>(nelems, repeat);
  Test< 512>(nelems, repeat);
  Test<1024>(nelems, repeat);

  return 0;
}
