// Mathematical specification and correctness notes (HPC formalism):
// Preconditions:
// - n_vectors >= 0, n_dimensions >= 0.
// - d_directions points to at least n_dimensions * n_directions 32-bit unsigned integers,
//   where n_directions is the width (in bits) of direction numbers used per dimension.
// - d_output points to a writable array of at least n_dimensions * n_vectors floats.
// - For each dimension d in [0, n_dimensions), the sub-array d_directions[d*n_directions + j]
//   contains the per-bit direction numbers v_j for j in [0, n_directions).
// - Grid configuration ensures stride = gridDim.x * blockDim.x is a power of two;
//   blockDim.x is a power of two; dimGrid.x is a power of two (enforced in sobolGPU).
//
// Postconditions:
// - For each dimension dim in [0, n_dimensions) and for each index i in [0, n_vectors),
//   d_output[dim*n_vectors + i] contains the i-th Sobol quasi-random variate in [0,1)
//   for that dimension, computed as float(X_i) * 2^-32, where X_i is obtained by
//   Gray-code xor of the direction numbers: X_i = XOR_{k | bit k of i's Gray code is 1} v_k.
// - No out-of-bounds memory accesses occur; other elements of d_output remain unmodified.
//
// Loop invariants and proof sketches of semantic equivalence after optimization:
//
// Invariant I0 (direction staging):
// - After __syncthreads(), shared array v[j] equals d_directions_dim[j] for all j in [0, n_directions).
// Preservation: Threads with threadIdx.x < n_directions copy v[j] = d_directions[j]; __syncthreads()
// guarantees visibility to all threads before any use.
//
// Invariant I1 (initial point computation):
// - Let g = i0 ^ (i0 >> 1) be the Gray code of i0. After the loop over k from 0 to (ffs(stride)-2),
//   X equals XOR_{k=0..(ffs(stride)-2)} (g_k ? v[k] : 0), where g_k is the k-th bit of g.
// Preservation: Each iteration processes the current LSB of g, conditionally xoring v[k] via mask,
// then right-shifts g. Unrolling does not alter logical order; all operations are associative/commutative xor.
//
// Invariant I2 (grid-stride recurrence):
// - For iteration variable i taking values i0 + stride*t (t>=1) while i < n_vectors,
//   X holds the correct Sobol integer for index i prior to the store, given by
//   X_i = X_{i - stride} xor v[log2(stride)-1] xor v[c], where
//   c = ffs(~((i - stride) | (stride - 1))) - 1 (the rightmost carry position).
// Preservation: This is the standard Owen/Bratley-Fox recurrence for jumping by power-of-two strides.
// We precompute v[log2(stride)-1] and v_stridemask=(stride-1) to keep recurrence intact.
// Each iteration updates X with the exact two toggled direction numbers, preserving the invariant.
//
// Structural changes that do not alter correctness:
// - Hoisting ffs(stride) and constants to registers does not change values.
// - Using a cached shared copy of v[] is observationally equivalent to direct global reads due to I0.
// - Using a streaming global store does not change stored values, only cache policy hints.
// - Changing block size from 64 to 256 preserves that stride is a power of two (since both are powers of two
//   and dimGrid.x is rounded up to a power of two), keeping all invariants and recurrences valid.

#define k_2powneg32 2.3283064E-10F

// Streaming store helper to reduce L1TEX write traffic pressure (Hopper supports .cs cache operator).
static __device__ __forceinline__ void store_streaming(float* addr, float val) {
#if defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 800)
    asm volatile("st.global.cs.f32 [%0], %1;" :: "l"(addr), "f"(val));
#else
    *addr = val;
#endif
}

__global__
void sobolGPU_kernel(unsigned n_vectors, unsigned n_dimensions,
                     unsigned *__restrict__ d_directions,
                     float *__restrict__ d_output)
{
    // Staging of per-dimension direction numbers in shared memory.
    // Assumes n_directions is provided (e.g., from sobol.h) and is <= 64.
    extern __shared__ unsigned int dynamic_smem[];
    unsigned int* v = dynamic_smem;

    // Offset to this block's dimension slice.
    d_directions += n_directions * blockIdx.y;
    d_output     += static_cast<size_t>(n_vectors) * blockIdx.y;

    // Load directions into shared memory (Invariant I0).
    if (threadIdx.x < n_directions) {
        v[threadIdx.x] = d_directions[threadIdx.x];
    }
    __syncthreads();

    // Thread-global index mapping and power-of-two grid stride.
    const unsigned i0     = threadIdx.x + blockIdx.x * blockDim.x;
    const unsigned stride = gridDim.x * blockDim.x;
    const unsigned ffs_stride = __ffs(stride); // 1 + log2(stride), since stride is power-of-two
    const unsigned log2_stride = ffs_stride - 1;

    // Initial Gray-code based construction of X for index i0 (Invariant I1).
    unsigned int g = i0 ^ (i0 >> 1);
    unsigned int X = 0u;

    // Only the lower (ffs_stride - 1) bits of Gray code affect X for the initial point
    // because subsequent higher bits are constant across grid-stride partition.
#pragma unroll 32
    for (unsigned int k = 0; k < (ffs_stride - 1); ++k) {
        unsigned int mask = -(g & 1u);
        X ^= (mask & v[k]);
        g >>= 1;
    }

    if (i0 < n_vectors) {
        // Streaming store to reduce L1TEX->XBAR write bandwidth pressure per metrics [1-3].
        store_streaming(&d_output[i0], static_cast<float>(X) * k_2powneg32);
    }

    // Prepare constants for the recurrence (Invariant I2).
    const unsigned int v_log2stridem1 = v[log2_stride - 1];
    const unsigned int v_stridemask   = stride - 1;

    // Grid-stride loop: advance by stride using the Sobol recurrence.
    // Loop invariant I2 holds before each iteration: X is the correct Sobol integer for (i - stride).
    for (unsigned int i = i0 + stride; i < n_vectors; i += stride) {
        // Toggle the two direction numbers that change when adding a power-of-two stride.
        // Index of the low-order zero after masking stride-1 determines carry position.
        X ^= (v_log2stridem1 ^ v[__ffs(~((i - stride) | v_stridemask)) - 1]);
        store_streaming(&d_output[i], static_cast<float>(X) * k_2powneg32);
    }
}

double sobolGPU(int repeat, int n_vectors, int n_dimensions,
                unsigned int *d_directions, float *d_output)
{
    // Increased threads per block to 256 for higher occupancy and better write coalescing on H100.
    // Keeps stride a power-of-two to preserve algorithmic invariants.
    const int threadsperblock = 256;

    dim3 dimGrid, dimBlock;
    dimGrid.y = n_dimensions;

    // Heuristic selection of dimGrid.x with an upper cap (4 * 24) and power-of-two rounding.
    if (n_dimensions < (4 * 24)) {
        dimGrid.x = 4 * 24;
    } else {
        dimGrid.x = 1;
    }
    if (dimGrid.x > (unsigned int)(n_vectors / threadsperblock)) {
        dimGrid.x = (n_vectors + threadsperblock - 1) / threadsperblock;
    }
    unsigned int targetDimGridX = (dimGrid.x == 0 ? 1 : dimGrid.x);
    for (dimGrid.x = 1; dimGrid.x < targetDimGridX; dimGrid.x <<= 1) {}

    dimBlock.x = threadsperblock;

    // Configure cache to favor shared/L2 balance on Hopper to alleviate L1TEX write pressure.
    cudaFuncSetCacheConfig(sobolGPU_kernel, cudaFuncCachePreferShared);

    // Shared memory size: n_directions 32-bit values staged per block.
    size_t smem_bytes = sizeof(unsigned int) * n_directions;

    cudaDeviceSynchronize();
    auto start = std::chrono::steady_clock::now();

    for (int i = 0; i < repeat; i++) {
        sobolGPU_kernel<<<dimGrid, dimBlock, smem_bytes>>>(
            n_vectors, n_dimensions, d_directions, d_output);
    }

    cudaDeviceSynchronize();
    auto end = std::chrono::steady_clock::now();
    double time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    return time;
}

