namespace cg = cooperative_groups;

// Sobol parameters: number of direction numbers per dimension (32 bits)
static constexpr unsigned n_directions = 32;
static constexpr float k_2powneg32 = 2.3283064e-10f;

// Preconditions and postconditions for sobolGPU_kernel:
//
// Preconditions:
// - d_directions points to an array of size at least n_dimensions * n_directions of 32-bit direction numbers.
// - For each dim y in [0, n_dimensions), the direction numbers for that dimension are contiguous,
//   at offset y*n_directions..y*n_directions+(n_directions-1).
// - d_output points to a writable array of size at least n_vectors * n_dimensions (laid out by dimension, i.e. blockIdx.y selects dimension).
// - gridDim.y == n_dimensions, and gridDim.x * blockDim.x (denoted stride) is a positive power of two (host config enforces this).
//
// Postconditions:
// - For each dimension y (0 <= y < n_dimensions) and each index i (0 <= i < n_vectors), d_output[y*n_vectors + i]
//   is the i-th Sobol sample in dimension y, equal to X(i, y) * 2^-32, where X(i, y) is produced by the standard
//   direction-number XOR recurrence using the provided direction table.
//
// Loop invariants (to guarantee semantic equivalence after optimization):
// - Shared table loading invariant:
//   After cg::wait(block), for all k in [0, n_directions), v[k] == d_directions[y*n_directions + k].
//   Proof sketch: cooperative_groups::memcpy_async enqueues a single block-wide copy from the source address
//   (&d_directions[y*n_directions]) to v. cg::wait(block) is a barrier that guarantees completion of this copy
//   for all threads in the block before proceeding. No other writes to v occur, so the invariant holds.
//
// - Initialization loop invariant (k-loop):
//   Before each iteration with index k, the variable g equals GrayCode(i0) >> k, and X equals XOR_{j in [0,k)} sel_j * v[j],
//   where sel_j is all-ones if the j-th bit of GrayCode(i0) is 1, else 0. The bound ffs_stride_minus1 = __ffs(stride)-1 is constant.
//   Proof sketch: Base k=0: g == GrayCode(i0), X==0 holds. Step: at iteration k, mask = -(g&1) selects v[k] if the current LSB of g is 1,
//   then X ^= mask & v[k] accumulates that contribution, and g >>= 1 removes that bit, maintaining the invariant. The loop bound is unchanged.
//
// - Strided update loop invariant (i-loop):
//   For each iteration where i equals i0 + m*stride with m >= 1, X holds the correct Sobol integer for index i - stride,
//   and the update X ^= v[log2(stride)-1] ^ v[j] with j = __ffs(~((i - stride) | (stride-1))) - 1 produces the correct Sobol integer for index i.
//   Proof sketch: This is the standard Gray-code based strided update for power-of-two stride. log2(stride) and (stride-1) are constant.
//   The expression for j finds the position of the rightmost zero among the low log2(stride) bits of (i - stride), as required by the Sobol
//   recurrence for jumping by stride. Since stride is a power of two, ffs_stride and v_stridemask are invariant, so the recurrence is preserved.
//   Therefore, the loop computes and writes the same sequence elements as the original code.
//
// Structural optimizations that preserve invariants:
// - Replacing per-thread shared-memory staging with cg::memcpy_async followed by cg::wait(block) is semantics-preserving,
//   as it provides an equivalent barriered copy of the same bytes from global to shared (shared table loading invariant).
// - Hoisting __ffs(stride) to a register (ffs_stride) and using its derived constants across the kernel does not change any outcome,
//   as stride is invariant per kernel launch configuration (and within a CTA). This reduces scoreboard stalls without altering logic.
// - Changing threadsperblock to a larger power-of-two (256) maintains the precondition that stride is a power of two and
//   preserves the distribution of indices across threads; the algorithm explicitly depends only on stride being a power of two.
//   The per-index result is identical because for any i, the recurrence and the value of v used are determined solely by i and stride.

__global__
void sobolGPU_kernel(unsigned n_vectors, unsigned n_dimensions,
                     unsigned *__restrict__ d_directions,
                     float *__restrict__ d_output)
{
    // Shared direction numbers for the selected dimension
    __shared__ unsigned int v[n_directions];

    // Compute dimension-specific pointers
    unsigned dim = blockIdx.y;
    unsigned *dirs_src = d_directions + n_directions * dim;
    float *out = d_output + n_vectors * dim;

    // Stage direction numbers to shared using Hopper-friendly async copy
    // (reduces stall_long_sb_ratio and stall_barrier_ratio vs. scalar loads + __syncthreads)
    cg::thread_block block = cg::this_thread_block();
    cg::memcpy_async(block, v, dirs_src, n_directions * sizeof(unsigned));
    cg::wait(block); // ensures v[] is fully populated and visible to all threads in the block

    // Thread's initial index and grid-wide stride (power of two)
    int i0     = threadIdx.x + blockIdx.x * blockDim.x;
    int stride = gridDim.x * blockDim.x;

    // Precompute invariant quantities from stride
    unsigned ffs_stride = __ffs(stride);                 // position of least-significant 1 bit (1-based)
    unsigned ffs_stride_minus1 = ffs_stride - 1;         // used as loop bound
    unsigned log2stridem1_idx = ffs_stride - 2;          // index = log2(stride)-1
    unsigned int v_log2stridem1 = v[log2stridem1_idx];   // invariant across the i-loop
    unsigned int v_stridemask = stride - 1;              // mask of low log2(stride) bits

    // Initial Gray code and base Sobol integer X at i0
    unsigned int g = static_cast<unsigned int>(i0) ^ (static_cast<unsigned int>(i0) >> 1);
    unsigned int X = 0;

    // Build X by accumulating contributions from the low (ffs_stride-1) bits of the Gray code
    // Loop invariant: see header comment. Bound is constant -> enables unrolling and reduces branch resolving stalls.
    #pragma unroll
    for (unsigned int k = 0; k < ffs_stride_minus1; ++k)
    {
        unsigned int mask = -(g & 1u);
        X ^= (mask & v[k]);
        g >>= 1;
    }

    if (i0 < static_cast<int>(n_vectors))
    {
        out[i0] = static_cast<float>(X) * k_2powneg32;
    }

    // Strided recurrence to produce subsequent Sobol integers spaced by 'stride'
    for (unsigned int i = i0 + stride; i < n_vectors; i += stride)
    {
        // Update from previous index (i - stride) to i using the standard power-of-two stride recurrence
        // j = index of the rightmost zero bit among the low log2(stride) bits of (i - stride)
        unsigned int prev = i - stride;
        unsigned int j = __ffs(~(prev | v_stridemask)) - 1;
        X ^= v_log2stridem1 ^ v[j];
        out[i] = static_cast<float>(X) * k_2powneg32;
    }
}

double sobolGPU(int repeat, int n_vectors, int n_dimensions,
                unsigned int *d_directions, float *d_output)
{
    // Tuning for H100: use 256 threads per block to increase warp residency and hide memory latency
    const int threadsperblock = 256;

    dim3 dimGrid;
    dim3 dimBlock;

    dimGrid.y = n_dimensions;

    // Spread work on x to keep stride a power of two while offering enough parallelism
    if (n_dimensions < (4 * 24))
    {
        dimGrid.x = 4 * 24;
    }
    else
    {
        dimGrid.x = 1;
    }

    if (dimGrid.x > (unsigned int)(n_vectors / threadsperblock))
    {
        dimGrid.x = (n_vectors + threadsperblock - 1) / threadsperblock;
    }

    // Make dimGrid.x a power of two (required by kernel's stride invariants)
    unsigned int targetDimGridX = dimGrid.x;
    for (dimGrid.x = 1; dimGrid.x < targetDimGridX; dimGrid.x *= 2) {}

    dimBlock.x = threadsperblock;

    cudaDeviceSynchronize();
    auto start = std::chrono::steady_clock::now();

    for (int i = 0; i < repeat; i++)
        sobolGPU_kernel<<<dimGrid, dimBlock>>>(
            n_vectors, n_dimensions, d_directions, d_output);

    cudaDeviceSynchronize();
    auto end = std::chrono::steady_clock::now();
    double time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    return time;
}

// Simple test harness main: allocates buffers, initializes a dummy direction table, and measures runtime.
int main(int argc, char** argv)
{
    int n_vectors = (argc > 1) ? std::atoi(argv[1]) : (1 << 20);
    int n_dimensions = (argc > 2) ? std::atoi(argv[2]) : 8;
    int repeat = (argc > 3) ? std::atoi(argv[3]) : 10;

    assert(n_dimensions > 0 && n_vectors > 0);

    size_t dirs_elems = static_cast<size_t>(n_dimensions) * n_directions;
    size_t dirs_bytes = dirs_elems * sizeof(unsigned);
    size_t out_elems  = static_cast<size_t>(n_dimensions) * n_vectors;
    size_t out_bytes  = out_elems * sizeof(float);

    // Host init: simple non-zero direction numbers (for demonstration; real Sobol uses canonical direction tables)
    unsigned* h_dirs = (unsigned*)malloc(dirs_bytes);
    for (size_t d = 0; d < (size_t)n_dimensions; ++d) {
        for (unsigned k = 0; k < n_directions; ++k) {
            // Ensure directions are non-zero and vary by dimension and order
            h_dirs[d * n_directions + k] = 1u << (31 - k);
        }
    }

    unsigned* d_dirs = nullptr;
    float* d_out = nullptr;
    cudaMalloc(&d_dirs, dirs_bytes);
    cudaMalloc(&d_out, out_bytes);
    cudaMemcpy(d_dirs, h_dirs, dirs_bytes, cudaMemcpyHostToDevice);
    cudaMemset(d_out, 0, out_bytes);

    double ns = sobolGPU(repeat, n_vectors, n_dimensions, d_dirs, d_out);
    printf("Elapsed: %.3f ms (repeat=%d, dims=%d, vectors=%d)\n",
           ns * 1e-6, repeat, n_dimensions, n_vectors);

    cudaFree(d_out);
    cudaFree(d_dirs);
    free(h_dirs);
    return 0;
}
