#define k_2powneg32 2.3283064E-10F

// Mathematical preconditions and postconditions (for correctness of transformations):
// Preconditions:
// - For each dimension d in [0, n_dimensions), the array d_directions[d * n_directions + k] for k in [0, n_directions)
//   contains the 32-bit direction numbers for the Sobol sequence.
// - The grid configuration for x-dimension is a power of two (host ensures this) so that stride = gridDim.x * blockDim.x
//   is a power of two and log2_stride = __ffs(stride) - 1 is defined.
// - The algorithm assumes (common in practice) that log2(stride) <= n_directions. When this is not true, we clamp
//   indices to [0, n_directions) which preserves memory safety and leaves the sequence well-defined for the computed bits.
// Postconditions:
// - For each dimension blockIdx.y, for i in [0, n_vectors), d_output[i] is the Sobol quasi-random value in [0,1)
//   computed from the corresponding direction numbers and Gray code recurrence, identical to the original kernel.
//
// Loop invariants and proofs of preservation (comments inline near loops):
__global__
void sobolGPU_kernel(unsigned n_vectors, unsigned n_dimensions,
                     unsigned *__restrict__ d_directions,
                     float *__restrict__ d_output)
{
    // Offsets for current dimension (blockIdx.y)
    // Replace shared-memory staging with on-demand cached loads to remove __syncthreads()
    // and shared-memory scoreboard stalls (stall_short_sb_ratio, stall_wait_ratio).
    d_directions += n_directions * blockIdx.y;
    d_output     += n_vectors    * blockIdx.y;

    // Thread's starting index and grid stride
    int i0     = threadIdx.x + blockIdx.x * blockDim.x;
    int stride = gridDim.x  * blockDim.x;

    // Precompute values reused multiple times to reduce repeated work and branches
    unsigned log2_stride = __ffs(stride) - 1;                     // since stride is power-of-two
    unsigned k_limit     = (log2_stride < n_directions) ? log2_stride : n_directions;

    // Initial Gray code for i0
    unsigned int g = static_cast<unsigned>(i0) ^ (static_cast<unsigned>(i0) >> 1);

    // Compute initial X using the first k_limit bits
    // Loop invariant:
    //   After t iterations (0 <= t <= k_limit),
    //   - g == (g0 >> t), where g0 is initial Gray code for i0.
    //   - X == XOR over j in [0, t) of ( (g0 >> j) & 1 ? v[j] : 0 ),
    //     where v[j] are direction numbers.
    // Initialization: t=0 => X==0, g==g0 holds.
    // Maintenance: each step consumes one bit of g and XORs the corresponding v[j] if that bit was 1.
    // Termination: after k_limit iterations, X matches original loop's effect.
    unsigned int X = 0;
    #pragma unroll
    for (unsigned int k = 0; k < k_limit; ++k)
    {
        unsigned int bit = g & 1u;
        unsigned int mask = 0u - bit;
        // On-demand read from global using read-only cache
        unsigned int vk = __ldg(&d_directions[k]);
        X ^= (mask & vk);
        g >>= 1;
    }

    if (i0 < static_cast<int>(n_vectors))
    {
        d_output[i0] = static_cast<float>(X) * k_2powneg32;
    }

    // Prepare constants for recurrence across grid-stride progression
    // When log2_stride < 2 or index exceeds n_directions-1, equivalent contribution is zero.
    unsigned v_log2stridem1 = 0;
    if (log2_stride >= 2) {
        unsigned idx = log2_stride - 1;
        if (idx < n_directions) v_log2stridem1 = __ldg(&d_directions[idx]);
    }
    unsigned int v_stridemask = static_cast<unsigned>(stride - 1);

    // Grid-stride loop to fill subsequent elements
    // Loop invariant at top of iteration for current i:
    //   - X equals the Sobol value for index (i - stride), updated to index i using
    //     X ^= v[log2_stride-1] ^ v[t(i)], where t(i) = __ffs(~((i - stride) | v_stridemask)) - 1.
    //   - Memory safety: all accessed direction indices are clamped to [0, n_directions).
    // Proof of maintenance:
    //   - The original code updates X using the same formula. We compute the same indices and clamp identically
    //     when out of range to preserve defined behavior and memory safety.
    //   - We use read-only cached loads instead of shared memory; since d_directions is immutable during kernel
    //     execution, the values are identical and the XOR algebra is unchanged.
    for (unsigned int i = static_cast<unsigned>(i0 + stride); i < n_vectors; i += static_cast<unsigned>(stride))
    {
        unsigned int prev = i - static_cast<unsigned>(stride);
        unsigned int t = __ffs(~(prev | v_stridemask)) - 1;

        unsigned int vt = 0;
        if (t < n_directions) vt = __ldg(&d_directions[t]);

        X ^= (v_log2stridem1 ^ vt);
        d_output[i] = static_cast<float>(X) * k_2powneg32;
    }
}

double sobolGPU(int repeat, int n_vectors, int n_dimensions,
                unsigned int *d_directions, float *d_output)
{
    // Increase threads per block to improve occupancy on H100 and reduce stall_wait_ratio by hiding latency.
    // Maintain power-of-two grid.x (host ensures) to keep stride power-of-two.
    const int threadsperblock = 256;

    dim3 dimGrid;
    dim3 dimBlock;

    dimGrid.y = n_dimensions;

    if (n_dimensions < (4 * 24))
    {
        dimGrid.x = 4 * 24;
    }
    else
    {
        dimGrid.x = 1;
    }

    if (dimGrid.x > (unsigned int)(n_vectors / threadsperblock))
    {
        dimGrid.x = (n_vectors + threadsperblock - 1) / threadsperblock;
    }

    unsigned int targetDimGridX = dimGrid.x;
    for (dimGrid.x = 1 ; dimGrid.x < targetDimGridX ; dimGrid.x <<= 1);

    dimBlock.x = threadsperblock;

    CUDA_CHECK(cudaDeviceSynchronize());
    auto start = std::chrono::steady_clock::now();

    for (int i = 0; i < repeat; i++)
      sobolGPU_kernel <<<dimGrid, dimBlock>>> (
        static_cast<unsigned>(n_vectors), static_cast<unsigned>(n_dimensions), d_directions, d_output);

    CUDA_CHECK(cudaGetLastError());
    CUDA_CHECK(cudaDeviceSynchronize());
    auto end = std::chrono::steady_clock::now();
    double time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    return time;
}

