    d_directions += n_directions * blockIdx.y;
    d_output     += n_vectors    * blockIdx.y;

    // Compute indices and stride early to reduce dependency chains
    const int i0     = threadIdx.x + blockIdx.x * blockDim.x;
    const int stride = gridDim.x * blockDim.x;

    // Precompute p = __ffs(stride) - 1 (loop bound), constant for the block
    const unsigned p = (unsigned)__ffs(stride) - 1u; // p >= 1 because stride >= 2

    // Stage only the needed direction numbers [0..p-1] into shared memory.
    // This reduces shared memory traffic and short scoreboard stalls (PC SUMMARY: "stall_short_sb_ratio" on shared ops).
    __shared__ unsigned int v[n_directions];

    const unsigned m = (p < n_directions) ? p : n_directions;

    if (threadIdx.x < m) {
        // Use read-only cache path to reduce latency (ROOFLINE: high short scoreboard stalls)
        v[threadIdx.x] = __ldg(&d_directions[threadIdx.x]);
