    unsigned int g = (unsigned int)i0 ^ ((unsigned int)i0 >> 1);

    // Build initial X from Gray code bits (0..p-1)
    unsigned int X = 0u;
#pragma unroll 32
    for (unsigned int k = 0; k < m; ++k) {
        // Branchless conditional XOR selection
        unsigned int mask = -(g & 1u);
        X ^= (mask & v[k]);
        g >>= 1;
    }

    // Emit the first value if in range
    if (i0 < (int)n_vectors) {
