    // Precompute stride-dependent constants once (removes repeated __ffs; see PC SUMMARY hot spots)
    const unsigned int v_log2stridem1 = v[p - 1u];
    const unsigned int v_stridemask   = (unsigned int)stride - 1u;

    // Walk forward in the Sobol sequence with a stride, updating X incrementally.
    // Maintain a running output pointer to reduce address arithmetic.
    for (unsigned int i = (unsigned int)i0 + (unsigned int)stride; i < (unsigned int)n_vectors; i += (unsigned int)stride) {
