int main(int argc, char** argv)
{
    int repeat = 10;
    int n_vectors = (1 << 20);    // 1M samples per dimension
    int n_dimensions = 128;       // 128 dimensions

    if (argc >= 2) n_vectors = std::max(1, atoi(argv[1]));
    if (argc >= 3) n_dimensions = std::max(1, atoi(argv[2]));
    if (argc >= 4) repeat = std::max(1, atoi(argv[3]));

    size_t dir_size = (size_t)n_dimensions * n_directions;
    size_t out_size = (size_t)n_dimensions * (size_t)n_vectors;

    // Host buffers
    std::vector<unsigned> h_directions(dir_size);
    std::vector<float>    h_output(out_size, 0.0f);

    // Initialize direction numbers with a simple non-zero pattern per bit (stand-in)
    for (int d = 0; d < n_dimensions; ++d) {
        for (unsigned k = 0; k < n_directions; ++k) {
            // Use a simple primitive polynomial-like pattern for demo (not production-grade Sobol init)
            h_directions[d * n_directions + k] = 1u << k;
        }
    }

    // Device buffers
    unsigned* d_directions = nullptr;
    float*    d_output     = nullptr;
    cudaMalloc(&d_directions, dir_size * sizeof(unsigned));
    cudaMalloc(&d_output,     out_size * sizeof(float));

    cudaMemcpy(d_directions, h_directions.data(), dir_size * sizeof(unsigned), cudaMemcpyHostToDevice);
    cudaMemset(d_output, 0, out_size * sizeof(float));

    double time_ns = sobolGPU(repeat, n_vectors, n_dimensions, d_directions, d_output);

    cudaMemcpy(h_output.data(), d_output, out_size * sizeof(float), cudaMemcpyDeviceToHost);

    // Print timing
    printf("Time (ns): %.0f\n", time_ns);

    cudaFree(d_directions);
    cudaFree(d_output);
    return 0;
