#include <cuda.h>
#include <cuda_runtime.h>
#include <chrono>
#include <cstdio>
#include "sobol.h"
#include "sobol_gpu.h"

#ifndef n_directions
// Fallback for number of direction numbers (commonly 32 for 32-bit Sobol)
#define n_directions 32
#endif

#define k_2powneg32 2.3283064E-10F

/*
Mathematical Preconditions:
- n_directions ∈ N, 1 ≤ n_directions ≤ 32 (number of direction numbers per dimension).
- blockDim.x and gridDim.x are powers of two (host launcher enforces this for stride).
- d_directions points to a valid table of size at least n_dimensions * n_directions (unsigned int).
- For the current blockIdx.y dimension, the base pointer d_directions + n_directions * blockIdx.y addresses
  the direction numbers v[0..n_directions-1] for that dimension.
- d_output has storage for at least n_dimensions * n_vectors floats.

Postconditions:
- For each dimension dim = blockIdx.y and each 0 ≤ i < n_vectors processed by this block, d_output[dim*n_vectors + i]
  contains the Sobol quasi-random number in [0,1) computed as (X_i * 2^-32), where X_i is the integer Sobol value
  generated using the provided direction numbers for that dimension.

Loop invariants and correctness arguments:
- Let stride = gridDim.x * blockDim.x (power of two). Let L = log2(stride).
- Invariant I1 (first loop, Gray-code initialization):
  After k iterations (0 ≤ k ≤ L-1), with g_k being the right-shifted Gray code bitstream (g_{k+1} = g_k >> 1),
  the accumulator X equals XOR over { v[j] | 0 ≤ j < k and bit j of (i0 ^ (i0 >> 1)) is 1 }.
  Initialization: X=0 holds for k=0. Maintenance: iteration k conditionally XORs v[k] iff the k-th Gray bit is set,
  preserving the XOR-set membership definition. Termination: after k=L-1 iterations X encodes the Gray prefix appropriate
  for stride alignment, matching the original algorithm.
- Invariant I2 (main i-loop stride recurrence):
  Before each store at index i (i = i0 + m*stride, m ≥ 0), X equals the Sobol integer X_i for index i.
  The recurrence X_i = X_{i-stride} XOR v[L-1] XOR v[t(i)], where t(i) = ffs(~((i - stride) | (stride - 1))) - 1,
  is a standard Sobol stride-update identity when stride is a power of two. Base: For i=i0, X was initialized by I1
  and stored correctly. Maintenance: Given X_{i-stride} held in X, we update X with v[L-1] XOR v[t(i)], yielding X_i.
  Since we always compute t(i) from i and fetch v[t(i)] accurately, the invariant holds. Thus the final stored values
  match the original semantics for all i in range.

Structural optimization safety proof:
- We replaced shared-memory table lookups v[idx] with warp-level register broadcasting via __shfl_sync. Each warp lane l
  preloads v[l] into a register (dir_lane). Any v[idx] request is satisfied by shuffling from lane idx. Since the Sobol
  direction table is identical for all threads in the block's dimension and idx ∈ [0, n_directions-1], the retrieved
  value equals the shared-memory value it replaces. The warp-synchronous shuffle preserves the invariants I1 and I2
  because it is a pure data movement of constant table entries without side effects, and it does not alter control flow.
*/

__global__
void sobolGPU_kernel(unsigned n_vectors, unsigned n_dimensions,
                     unsigned *__restrict__ d_directions,
                     float *__restrict__ d_output)
{
    // Advance base pointers to this dimension
    d_directions += n_directions * blockIdx.y;
    d_output     += n_vectors    * blockIdx.y;

    // Thread and grid constants
    const unsigned int i0     = threadIdx.x + blockIdx.x * blockDim.x;
    const unsigned int stride = gridDim.x * blockDim.x;

    // Precompute small constants to avoid repeated __ffs(stride)
    const unsigned int ffs_stride      = __ffs(stride);             // = log2(stride) + 1
    const unsigned int log2_stride_m1  = (ffs_stride > 0) ? (ffs_stride - 1) : 0;  // = log2(stride)
    const unsigned int log2_stride_m2  = (ffs_stride >= 2) ? (ffs_stride - 2) : 0; // = log2(stride) - 1 if stride>=2
    const unsigned int v_stridemask    = stride - 1;

    // Build a warp-local register LUT for direction numbers: lane l holds v[l]
    const unsigned lane      = threadIdx.x & 31;
    const unsigned full_mask = __activemask();
    const unsigned dir_lane  = (lane < n_directions) ? __ldg(d_directions + lane) : 0u;

    // Initialize via Gray-code method up to log2(stride) bits
    unsigned int g = i0 ^ (i0 >> 1);
    unsigned int X = 0;

    #pragma unroll
    for (unsigned int k = 0; k < log2_stride_m1; ++k)
    {
        // Obtain v[k] via warp shuffle from lane k
        const unsigned int vk = __shfl_sync(full_mask, dir_lane, k, 32);
        const unsigned int mask = -(g & 1);
        X ^= mask & vk;
        g >>= 1;
    }

    if (i0 < n_vectors)
    {
        d_output[i0] = (float)X * k_2powneg32;
    }

    // Preload v[log2(stride)-1] via shuffle
    const unsigned int v_log2stridem1 = __shfl_sync(full_mask, dir_lane, log2_stride_m2, 32);

    // Stride loop using Sobol recurrence
    for (unsigned int i = i0 + stride; i < n_vectors; i += stride)
    {
        // Compute index of rightmost zero bit crossing for update
        const unsigned int t = __ffs(~((i - stride) | v_stridemask)) - 1;
        const unsigned int v_t = __shfl_sync(full_mask, dir_lane, t, 32);
        X ^= v_log2stridem1 ^ v_t;
        d_output[i] = (float)X * k_2powneg32;
    }
}

