  float4 v0 = init_val(tid);
  float4 v1 = init_val(tid+1);
  float4 v2 = init_val(tid+3);
  float4 v3 = init_val(tid+7);
  float4 v4 = init_val(tid+13);
  float4 v5 = init_val(tid+17);

